import React, { createContext, useContext, useState, useEffect } from 'react';

const DEFAULT_BOOK = {
  title: 'The Cosmos Within',
  author: 'Eleanor Voss',
  subtitle: 'A Journey Through Space and Mind',
  coverColor: '#302b63',
  pages: [
    {
      id: 'p1',
      chapter: 'Chapter I',
      title: 'The First Light',
      content: 'In the beginning, there was silence — a silence so deep it had weight, texture, and colour. Astronomers call it the cosmic dark age: a billion years when no stars existed, no light pierced the hydrogen fog, and the universe held its breath.\n\nThen, like a thought forming in a sleeping mind, matter gathered. Gas clouds collapsed under their own gravity. Temperatures rose. Pressures climbed. And in the heart of the first star, hydrogen fused into helium, releasing a photon that had waited since the dawn of time.\n\nThat first light still travels. Redshifted into the microwave, it whispers the universe\'s oldest secret to anyone patient enough to listen.',
      quote: 'Every atom in your body was forged in a star.',
      image: null,
      imageCaption: '',
      textStyle: 'normal',
    },
    {
      id: 'p2',
      chapter: 'Chapter I',
      title: 'Star Stuff',
      content: 'We are made of star stuff — not metaphorically, but literally. The carbon in your DNA, the iron in your blood, the calcium in your bones: all forged in nuclear fires that burned for millions of years before exploding outward in supernovae.\n\nThis is perhaps the most astonishing fact science has revealed: you are the universe experiencing itself. Every thought you think is a pattern of electrical signals in neurons built from recycled stardust.\n\nWhen you look up at the night sky, you are not looking outward. You are looking at yourself — at what you were before you were you.',
      quote: 'The cosmos is within us.',
      image: null,
      imageCaption: '',
      textStyle: 'normal',
    },
    {
      id: 'p3',
      chapter: 'Chapter II',
      title: 'The Scale of Everything',
      content: 'Numbers fail us when we try to comprehend the universe\'s scale. A light-year — the distance light travels in a year — is approximately 9.46 trillion kilometres. The nearest star beyond our sun is 4.24 light-years away. The Milky Way stretches 100,000 light-years across.\n\nAnd the observable universe? Forty-six billion light-years in every direction. Not because the universe is that old — it is only 13.8 billion years old — but because space itself expanded while that light was traveling.\n\nBeyond the observable universe, the cosmos continues. Perhaps infinitely.',
      quote: 'Space is big. Really big.',
      image: null,
      imageCaption: '',
      textStyle: 'normal',
    },
    {
      id: 'p4',
      chapter: 'Chapter II',
      title: 'Dark Matters',
      content: 'Ninety-five percent of the universe is invisible. Not merely dim — invisible. Dark matter does not emit, absorb, or reflect light. We know it exists only because of its gravitational effects: galaxies spin too fast, light bends too much, and the large-scale structure of the cosmos makes no sense without it.\n\nDark energy is stranger still. It does not just refuse to interact with light — it actively pushes space apart. The universe is not merely expanding; it is accelerating.\n\nWe have not named things we understand. We have named things we do not yet understand.',
      quote: 'The universe hides more than it reveals.',
      image: null,
      imageCaption: '',
      textStyle: 'normal',
    },
    {
      id: 'p5',
      chapter: 'Chapter III',
      title: 'Are We Alone?',
      content: 'The Drake equation estimates the number of civilizations in our galaxy capable of communication. Its variables span orders of magnitude in uncertainty.\n\nYet the Fermi paradox haunts us: if intelligent life is common, where is everyone? The universe is 13.8 billion years old. Even at a fraction of light speed, a civilization could colonize the entire galaxy in a few hundred million years.\n\nThe Great Silence may mean we are alone. Or it may mean intelligent life always destroys itself. Or that they are watching, waiting. Or that they communicate in ways we have not yet conceived.',
      quote: 'Two possibilities exist: alone, or not.',
      image: null,
      imageCaption: '',
      textStyle: 'normal',
    },
    {
      id: 'p6',
      chapter: 'Chapter III',
      title: 'The Pale Blue Dot',
      content: 'On February 14, 1990, Voyager 1 was commanded to turn its camera back toward the inner solar system. At a distance of about 6 billion kilometres, it photographed Earth: a pale blue dot, a mote of dust suspended in a sunbeam.\n\nCarl Sagan wrote: our planet is a lonely speck in the great enveloping cosmic dark. In our obscurity, in all this vastness, there is no hint that help will come from elsewhere to save us from ourselves.\n\nThe Earth is the only world known, so far, to harbour life. There is nowhere else, at least in the near future, to which our species could migrate. Visit, yes. Settle, not yet.',
      quote: 'A mote of dust suspended in a sunbeam.',
      image: null,
      imageCaption: '',
      textStyle: 'normal',
    },
  ],
};

const BookContext = createContext(null);

export function BookProvider({ children }) {
  const [book, setBook] = useState(() => {
    try {
      const saved = localStorage.getItem('cosmicBook');
      return saved ? JSON.parse(saved) : DEFAULT_BOOK;
    } catch {
      return DEFAULT_BOOK;
    }
  });

  useEffect(() => {
    localStorage.setItem('cosmicBook', JSON.stringify(book));
  }, [book]);

  const updateBook = (updates) => setBook(b => ({ ...b, ...updates }));

  const addPage = () => {
    const newPage = {
      id: 'p' + Date.now(),
      chapter: 'New Chapter',
      title: 'New Page',
      content: 'Start writing your content here...',
      quote: '',
      image: null,
      imageCaption: '',
      textStyle: 'normal',
    };
    setBook(b => ({ ...b, pages: [...b.pages, newPage] }));
    return newPage.id;
  };

  const updatePage = (id, updates) => {
    setBook(b => ({
      ...b,
      pages: b.pages.map(p => p.id === id ? { ...p, ...updates } : p),
    }));
  };

  const deletePage = (id) => {
    setBook(b => ({ ...b, pages: b.pages.filter(p => p.id !== id) }));
  };

  const movePage = (id, dir) => {
    setBook(b => {
      const pages = [...b.pages];
      const idx = pages.findIndex(p => p.id === id);
      const newIdx = idx + dir;
      if (newIdx < 0 || newIdx >= pages.length) return b;
      [pages[idx], pages[newIdx]] = [pages[newIdx], pages[idx]];
      return { ...b, pages };
    });
  };

  const resetBook = () => setBook(DEFAULT_BOOK);

  return (
    <BookContext.Provider value={{ book, updateBook, addPage, updatePage, deletePage, movePage, resetBook }}>
      {children}
    </BookContext.Provider>
  );
}

export const useBook = () => useContext(BookContext);
